// Create EC2 instance via Custom Resource with failover support
var ec2InstanceResource = CustomResource.Builder.create(this, "IdeEC2InstanceResource")
    .serviceToken(launcherFunction.getFunction().getFunctionArn())
    .properties(Map.of(
        "SubnetIds", String.join(",", publicSubnets.getSubnetIds()),
        "InstanceTypes", "m5.xlarge,m6i.xlarge,t3.xlarge",
        "ImageId", MachineImage.latestAmazonLinux2023().getImage(this).getImageId(),
        "SecurityGroupIds", String.join(",", securityGroupIds),
        "IamInstanceProfileArn", instanceProfile.getInstanceProfileArn(),
        "VolumeSize", "50",
        "InstanceName", instanceName,
        "UserData", Fn.base64(userData.render())
    ))
    .build();

String instanceId = ec2InstanceResource.getAttString("InstanceId");

args.newStr:
// Create Launch Template with mixed instance types for failover
var launchTemplate = LaunchTemplate.Builder.create(this, "IdeLaunchTemplate")
    .launchTemplateName(instanceName + "-template")
    .machineImage(MachineImage.latestAmazonLinux2023())
    .instanceType(InstanceType.of(InstanceClass.M5, InstanceSize.XLARGE)) // Primary instance type
    .securityGroup(ideSecurityGroup)
    .userData(userData)
    .role(roles.getWorkshopRole())
    .blockDevices(List.of(BlockDevice.builder()
        .deviceName("/dev/xvda")
        .volume(BlockDeviceVolume.ebs(50, EbsDeviceOptions.builder()
            .volumeType(EbsDeviceVolumeType.GP3)
            .deleteOnTermination(true)
            .build()))
        .build()))
    .build();

// Add additional security group to launch template
launchTemplate.getConnections().addSecurityGroup(ideInternalSecurityGroup);

// Create Auto Scaling Group with mixed instance types for failover
var autoScalingGroup = AutoScalingGroup.Builder.create(this, "IdeAutoScalingGroup")
    .vpc(vpc)
    .vpcSubnets(publicSubnets)
    .launchTemplate(launchTemplate)
    .minCapacity(1)
    .maxCapacity(1)
    .desiredCapacity(1)
    .autoScalingGroupName(instanceName + "-asg")
    .mixedInstancesPolicy(MixedInstancesPolicy.builder()
        .instancesDistribution(InstancesDistribution.builder()
            .onDemandPercentageAboveBaseCapacity(100) // Use only On-Demand instances
            .build())
        .launchTemplateOverrides(List.of(
            LaunchTemplateOverrides.builder()
                .instanceType(InstanceType.of(InstanceClass.M5, InstanceSize.XLARGE))
                .build(),
            LaunchTemplateOverrides.builder()
                .instanceType(InstanceType.of(InstanceClass.M6I, InstanceSize.XLARGE))
                .build(),
            LaunchTemplateOverrides.builder()
                .instanceType(InstanceType.of(InstanceClass.T3, InstanceSize.XLARGE))
                .build()
        ))
        .build())
    .build();

// Add tags to instances
autoScalingGroup.getNode().getChildren().forEach(child -> {
    if (child instanceof CfnAutoScalingGroup) {
        ((CfnAutoScalingGroup) child).setTags(List.of(
            CfnAutoScalingGroup.TagPropertyProperty.builder()
                .key("Name")
                .value(instanceName)
                .propagateAtLaunch(true)
                .build(),
            CfnAutoScalingGroup.TagPropertyProperty.builder()
                .key("Workshop")
                .value("true")
                .propagateAtLaunch(true)
                .build()
        ));
    }
});

// Get the instance ID from the Auto Scaling Group (for EIP association)
// We'll use a custom resource to get the instance ID from the ASG
var getInstanceIdFunction = Function.Builder.create(this, "GetInstanceIdFunction")
    .runtime(Runtime.PYTHON_3_13)
    .handler("index.handler")
    .code(Code.fromInline("""
        import boto3
        import json

        def handler(event, context):
            if event['RequestType'] == 'Delete':
                return {'PhysicalResourceId': 'none'}

            asg_name = event['ResourceProperties']['AutoScalingGroupName']

            asg_client = boto3.client('autoscaling')
            response = asg_client.describe_auto_scaling_groups(
                AutoScalingGroupNames=[asg_name]
            )

            if not response['AutoScalingGroups']:
                raise Exception(f'Auto Scaling Group {asg_name} not found')

            instances = response['AutoScalingGroups'][0]['Instances']
            if not instances:
                raise Exception(f'No instances found in Auto Scaling Group {asg_name}')

            instance_id = instances[0]['InstanceId']

            return {
                'PhysicalResourceId': instance_id,
                'Data': {
                    'InstanceId': instance_id
                }
            }
        """))
    .timeout(Duration.minutes(5))
    .role(roles.getLambdaRole())
    .build();

var instanceIdResource = CustomResource.Builder.create(this, "IdeInstanceIdResource")
    .serviceToken(getInstanceIdFunction.getFunctionArn())
    .properties(Map.of(
        "AutoScalingGroupName", autoScalingGroup.getAutoScalingGroupName()
    ))
    .build();

String instanceId = instanceIdResource.getAttString("InstanceId");

