var ec2Fleet = CfnSpotFleet.Builder.create(this, "IdeFleet")
    .spotFleetRequestConfigData(CfnSpotFleet.SpotFleetRequestConfigDataProperty.builder()
        .targetCapacity(1) // We only need 1 instance
        .allocationStrategy("diversified") // Try all combinations systematically
        .iamFleetRole(roles.getLambdaRole().getRoleArn()) // Fleet service role
        .type("maintain") // Maintain target capacity
        .launchSpecifications(List.of(
            // m5.xlarge in AZ 1
            createFleetLaunchSpec("m5.xlarge", publicSubnets.getSubnetIds().get(0), 
                instanceProfile, userData, instanceName),
            // m5.xlarge in AZ 2  
            createFleetLaunchSpec("m5.xlarge", publicSubnets.getSubnetIds().get(1),
                instanceProfile, userData, instanceName),
            // m6i.xlarge in AZ 1
            createFleetLaunchSpec("m6i.xlarge", publicSubnets.getSubnetIds().get(0),
                instanceProfile, userData, instanceName),
            // m6i.xlarge in AZ 2
            createFleetLaunchSpec("m6i.xlarge", publicSubnets.getSubnetIds().get(1),
                instanceProfile, userData, instanceName),
            // t3.xlarge in AZ 1
            createFleetLaunchSpec("t3.xlarge", publicSubnets.getSubnetIds().get(0),
                instanceProfile, userData, instanceName),
            // t3.xlarge in AZ 2
            createFleetLaunchSpec("t3.xlarge", publicSubnets.getSubnetIds().get(1),
                instanceProfile, userData, instanceName)
        ))
        .build())
    .build();

// Simple Lambda to get instance ID from Fleet (much simpler than original launcher)
var getFleetInstanceFunction = Function.Builder.create(this, "GetFleetInstanceFunction")
    .runtime(Runtime.PYTHON_3_13)
    .handler("index.handler")
    .code(Code.fromInline("""
        import boto3

        def handler(event, context):
            if event['RequestType'] == 'Delete':
                return {'PhysicalResourceId': 'none'}

            fleet_id = event['ResourceProperties']['FleetId']

            ec2 = boto3.client('ec2')
            response = ec2.describe_spot_fleet_instances(SpotFleetRequestId=fleet_id)

            if not response['ActiveInstances']:
                raise Exception(f'No active instances in fleet {fleet_id}')

            instance_id = response['ActiveInstances'][0]['InstanceId']

            return {
                'PhysicalResourceId': instance_id,
                'Data': {'InstanceId': instance_id}
            }
        """))
    .timeout(Duration.minutes(2))
    .role(roles.getLambdaRole())
    .build();

var fleetInstanceResource = CustomResource.Builder.create(this, "IdeFleetInstanceResource")
    .serviceToken(getFleetInstanceFunction.getFunctionArn())
    .properties(Map.of("FleetId", ec2Fleet.getRef()))
    .build();

String instanceId = fleetInstanceResource.getAttString("InstanceId");

